import React from 'react';
import { Link, Navigate, useParams } from 'react-router-dom';
import ServiceImagePlaceholder from '../components/services/ServiceImagePlaceholder';
import { SERVICE_PAGE_BG } from '../constants/servicePageVisual';
import { getServiceBySlug, processSteps } from '../data/servicePages';
import './ServiceDetail.css';
import '../styles/servicePageBackground.css';

const ServiceDetail = () => {
  const { serviceSlug } = useParams();
  const service = getServiceBySlug(serviceSlug);

  if (!service) {
    return <Navigate to="/services" replace />;
  }

  const slots = service.imageSlots || [];

  return (
    <div
      className="service-detail-page"
      style={{ '--service-page-bg-image': SERVICE_PAGE_BG }}
    >
      <section className="service-hero">
        <div className="container">
          <span className="eyebrow">{service.category}</span>
          <h1>{service.title}</h1>
          <p>{service.heroDescription}</p>
          {service.introExtra && <p className="service-hero-extra">{service.introExtra}</p>}
          <Link to="/contact" className="btn-primary btn-large">
            Submit Your Query
          </Link>
        </div>
      </section>

      {slots[0] && (
        <ServiceImagePlaceholder label={slots[0].label} sizeHint={slots[0].sizeHint} />
      )}

      <section className="service-section">
        <div className="container">
          <h2>The challenges</h2>
          <ul className="service-list">
            {service.problems.map((item) => (
              <li key={item}>{item}</li>
            ))}
          </ul>
        </div>
      </section>

      <section className="service-section">
        <div className="container">
          <h2>How we help</h2>
          <ul className="service-list">
            {service.solutions.map((item) => (
              <li key={item}>{item}</li>
            ))}
          </ul>
        </div>
      </section>

      <section className="service-section">
        <div className="container">
          <h2>What&apos;s included</h2>
          <ul className="service-list">
            {service.included.map((item) => (
              <li key={item}>{item}</li>
            ))}
          </ul>
        </div>
      </section>

      {slots[1] && (
        <ServiceImagePlaceholder label={slots[1].label} sizeHint={slots[1].sizeHint} />
      )}

      <section className="service-section">
        <div className="container">
          <h2>Who it&apos;s for</h2>
          <ul className="service-list">
            {service.audience.map((item) => (
              <li key={item}>{item}</li>
            ))}
          </ul>
        </div>
      </section>

      <section className="service-section">
        <div className="container">
          <h2>How the service works</h2>
          <div className="service-process">
            {processSteps.map((step, index) => (
              <div key={step.title} className="service-process-step">
                <div className="num">{index + 1}</div>
                <div>
                  <h3>{step.title}</h3>
                  <p>{step.text}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section className="service-cta-bar">
        <div className="container">
          <p>Ready to get started? Tell us what you need.</p>
          <Link to="/contact" className="btn-primary btn-large">
            Submit Your Query
          </Link>
        </div>
      </section>
    </div>
  );
};

export default ServiceDetail;
